'use server';

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";

export async function uploadOrcamentoAction(formData: FormData) {
    const supabase = await createClient();

    const file = formData.get('file') as File;
    
    if (!file) {
        return { success: false, error: "Nenhum arquivo enviado." };
    }

    if (file.type !== "application/pdf") {
         return { success: false, error: "Apenas arquivos PDF são aceitos." };
    }

    if (file.size > 10 * 1024 * 1024) { // 10MB limit
         return { success: false, error: "O arquivo excede o limite de 10MB." };
    }

    const fileExt = file.name.split('.').pop();
    const fileName = `${crypto.randomUUID()}.${fileExt}`;
    const filePath = `orcamentos/${fileName}`; // Assuming bucket structure

    const { data: uploadData, error: uploadError } = await supabase.storage
        .from('orcamentos_pdfs')
        .upload(filePath, file, {
            contentType: 'application/pdf',
            upsert: false
        });

    if (uploadError) {
        console.error("Upload error:", uploadError);
        return { success: false, error: "Erro ao fazer upload do arquivo. Tente novamente." };
    }

    // Passar o file path via URL_SearchParams ou rota. 
    // Como nâo sabemos se o `jobs` na tabela já existe, usaremos query params para o Mock Revision MVP
    const path = encodeURIComponent(uploadData.path);
    
    // In a real app we'd insert into `import_jobs`, get an ID and redirect to `/import/${job_id}`.
    // Given the instructions, we redirect to a mock URL containing the path. We will redirect to /import/revisao?file=...
    // The user instruction mentioned "ex: /import/[job_id] ou /import/revisao?file=[path]"
    
    redirect(`/import/revisao?file=${path}`);
}
